begin;create extension if not exists pgtap with schema extensions;set local search_path=extensions,public,pg_catalog;select plan(12);
select has_table('private','destructive_audit_events','minimal destructive audit exists');
select has_function('api','hard_delete_round',array['uuid','integer','text'],'hard delete RPC exists');
select col_is_fk('app','predictions','round_id','predictions are bound to a round');
select col_is_fk('app','prediction_scores','round_id','scores are bound to a round');
select ok(not has_table_privilege('authenticated','private.destructive_audit_events','SELECT'),'audit is not client-readable');
select ok(not exists(select 1 from pg_constraint where conrelid='private.destructive_audit_events'::regclass and contype='f'),'audit deliberately has no foreign keys');
insert into app.leagues(id,name,short_name)values('61000000-0000-4000-8000-000000000001','Delete Liga','DL');
insert into app.seasons(id,label,starts_on,ends_on)values('61000000-0000-4000-8000-000000000002','Delete 26/27','2026-07-01','2027-06-30');
insert into app.league_seasons(id,league_id,season_id)values('61000000-0000-4000-8000-000000000003','61000000-0000-4000-8000-000000000001','61000000-0000-4000-8000-000000000002');set constraints all deferred;
insert into app.prediction_rounds(id,name,league_season_id,owner_membership_id)values('61000000-0000-4000-8000-000000000004','Exakt löschen','61000000-0000-4000-8000-000000000003','61000000-0000-4000-8000-000000000005');
insert into app.round_memberships(id,round_id,user_id,nickname,role)values('61000000-0000-4000-8000-000000000005','61000000-0000-4000-8000-000000000004','00000000-0000-4000-8000-000000000003','Owner','owner');
select set_config('request.jwt.claim.sub','00000000-0000-4000-8000-000000000003',true);set local role authenticated;
select throws_ok($$select api.hard_delete_round('61000000-0000-4000-8000-000000000004',1,'falsch')$$,'22023','Exact round name confirmation required','wrong name aborts delete');reset role;
select is((select count(*) from app.prediction_rounds where id='61000000-0000-4000-8000-000000000004'),1::bigint,'failed confirmation leaves round intact');
set local role authenticated;select lives_ok($$select api.hard_delete_round('61000000-0000-4000-8000-000000000004',1,'Exakt löschen')$$,'exact name commits delete');reset role;
select is((select count(*) from app.prediction_rounds where id='61000000-0000-4000-8000-000000000004'),0::bigint,'round is gone');
select is((select count(*) from app.league_seasons where id='61000000-0000-4000-8000-000000000003'),1::bigint,'global league season remains');
select is((select count(*) from private.destructive_audit_events where object_id='61000000-0000-4000-8000-000000000004' and actor_id='00000000-0000-4000-8000-000000000003' and action='round_hard_deleted'),1::bigint,'one minimal audit event remains');
select * from finish();rollback;
